@ob-stripe I'm able to reduce the amount of code change needed from changing `APIRequestor.request` by doing this little awkward bit. Essentially unpacking the response body dict inside `convert_to_stripe_object`.

`APIRequestor.request`'s only real consumer is `convert_to_stripe_object` we only need to change it here.

wdyt?

i prepared the following code to unblock a cust:

```scala
import org.apache.spark.sql.Column
import org.apache.spark.sql.types._
import org.apache.spark.sql.functions._

def flattenSchema(schema: StructType, prefix: String = null) : Array[Column] = {
  schema.fields.flatMap(f => {
    val colPath = if (prefix == null) s"`${f.name}`" else s"${prefix}.`${f.name}`"

    f.dataType match {
      case st: StructType => flattenSchema(st, colPath)
      // Skip user defined types like array or vectors
      case x if x.isInstanceOf[ArrayType] => Array.empty[Column]
      case _ => Array(col(colPath).alias(colPath.replaceAll("[.`]", "_")))
    }
  })
}

val df = spark.read.parquet("/tmp/blahala.csv")
df.select(flattenSchema(df.schema):_*).write.csv("/tmp/xxx.csv")```

